#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long P, L;
        scanf("%lld %lld", &P, &L);
        if (L * 4LL >= 3LL * P) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

